import React from "react";
import { NavLink, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import { getDashboardPathByRole } from "../utils/auth";

function Navbar() {
	const navigate = useNavigate();
	const { user, logoutUser } = useAuth();

	const isAdmin = user?.role === "ADMIN";

	const handleLogout = () => {
		logoutUser();
		navigate("/");
	};

	return (
		<nav className="app-navbar">
			<div className="container d-flex flex-wrap align-items-center justify-content-between gap-3 py-3">
				<NavLink className="brand-mark" to={getDashboardPathByRole(user?.role)}>
					<span className="brand-badge">CMS</span>
					<span>ComplianceAI</span>
				</NavLink>

				<div className="app-nav-links">
					<NavLink
						className={({ isActive }) => `app-nav-link${isActive ? " active" : ""}`}
						to={isAdmin ? "/admin/dashboard" : "/user/dashboard"}
					>
						Dashboard
					</NavLink>
					{isAdmin ? (
						<>
							<NavLink
								className={({ isActive }) => `app-nav-link${isActive ? " active" : ""}`}
								to="/admin/complaints"
							>
								View Complaints
							</NavLink>
							<NavLink
								className={({ isActive }) => `app-nav-link${isActive ? " active" : ""}`}
								to="/admin/reports"
							>
								Reports
							</NavLink>
						</>
					) : (
						<>
							<NavLink
								className={({ isActive }) => `app-nav-link${isActive ? " active" : ""}`}
								to="/complaints/add"
							>
								Submit Complaint
							</NavLink>
							<NavLink
								className={({ isActive }) => `app-nav-link${isActive ? " active" : ""}`}
								to="/complaints"
							>
								Track Status
							</NavLink>
						</>
					)}
					{isAdmin && (
						<NavLink
							className={({ isActive }) => `app-nav-link${isActive ? " active" : ""}`}
							to="/admin/complaints"
						>
							Case Queue
						</NavLink>
					)}
				</div>

				<div className="d-flex align-items-center gap-2">
					<span className="role-pill">
						{user?.name || "User"} ({user?.role || "USER"})
					</span>
					<button className="btn btn-sm btn-dark" onClick={handleLogout}>
						Logout
					</button>
				</div>
			</div>
		</nav>
	);
}

export default Navbar;
